public static boolean isVersionCompatible(String current, String required) {
    String[] currentParts = current.split("\\.");
    String[] requiredParts = required.split("\\.");
    for (int i = 0; i < Math.min(currentParts.length, requiredParts.length); i++) {
        int cmp = Integer.compare(Integer.parseInt(currentParts[i]), Integer.parseInt(requiredParts[i]));
        if (cmp != 0) return cmp >= 0;
    }
    return currentParts.length >= requiredParts.length;
}

